#ifndef RMSNORM_H7168_KERNEL_H_
#define RMSNORM_H7168_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#define HIDDEN_SIZE_7168 7168
#define RMSNORM_EPS 1.0e-6f

// Host launcher (signature must remain stable)
void rmsnorm_h7168_launch(
    const __nv_bfloat16* hidden_states, // [B, 7168]
    const __nv_bfloat16* weight,        // [7168]
    __nv_bfloat16* output,              // [B, 7168]
    int64_t batch_size,
    cudaStream_t stream);

#endif // RMSNORM_H7168_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

// --------- reductions ----------
static __device__ __forceinline__ float warp_sum(float v) {
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

static __device__ __forceinline__ float block_sum(float v) {
  __shared__ float smem[32]; // up to 1024 threads
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  v = warp_sum(v);
  if (lane == 0) smem[warp] = v;
  __syncthreads();

  float out = 0.f;
  if (warp == 0) {
    int nwarps = (blockDim.x + 31) >> 5;
    out = (lane < nwarps) ? smem[lane] : 0.f;
    out = warp_sum(out);
  }
  out = __shfl_sync(0xffffffff, out, 0);
  return out;
}

// --------- bf16x2 helpers (alignment-safe without memcpy headers) ----------
// Avoid memcpy in device code (can cause toolchain/runtime issues). Use byte-wise load/store.
// Works for any alignment; performance is fine for contiguous tensors on A800.
static __device__ __forceinline__ __nv_bfloat162 ld_bf16x2_any(const __nv_bfloat16* p) {
  __nv_bfloat162 out;
  // Treat as 4 bytes
  const unsigned char* src = reinterpret_cast<const unsigned char*>(p);
  unsigned char* dst = reinterpret_cast<unsigned char*>(&out);
#pragma unroll
  for (int i = 0; i < 4; ++i) dst[i] = src[i];
  return out;
}

static __device__ __forceinline__ void st_bf16x2_any(__nv_bfloat16* p, __nv_bfloat162 v) {
  unsigned char* dst = reinterpret_cast<unsigned char*>(p);
  const unsigned char* src = reinterpret_cast<const unsigned char*>(&v);
#pragma unroll
  for (int i = 0; i < 4; ++i) dst[i] = src[i];
}

// Constant memory weight cache (14KB)
__device__ __constant__ __nv_bfloat16 c_weight[HIDDEN_SIZE_7168];

__global__ void rmsnorm_h7168_kernel_constw(
    const __nv_bfloat16* __restrict__ x,
    __nv_bfloat16* __restrict__ y,
    int64_t batch_size) {

  int row = (int)blockIdx.x;
  if ((int64_t)row >= batch_size) return;

  constexpr int H = HIDDEN_SIZE_7168;
  constexpr int VEC2 = H / 2; // 3584

  const int tid = threadIdx.x;
  const int base = row * H;

  float sumsq = 0.f;

#pragma unroll 4
  for (int i = tid; i < VEC2; i += (int)blockDim.x) {
    int col = i * 2;
    __nv_bfloat162 vx2 = ld_bf16x2_any(x + base + col);
    float2 xf = __bfloat1622float2(vx2);
    sumsq = fmaf(xf.x, xf.x, sumsq);
    sumsq = fmaf(xf.y, xf.y, sumsq);
  }

  float total = block_sum(sumsq);
  float inv_rms = rsqrtf(total * (1.0f / (float)H) + RMSNORM_EPS);

#pragma unroll 4
  for (int i = tid; i < VEC2; i += (int)blockDim.x) {
    int col = i * 2;

    __nv_bfloat162 vx2 = ld_bf16x2_any(x + base + col);
    __nv_bfloat162 vw2 = ld_bf16x2_any(c_weight + col);

    float2 xf = __bfloat1622float2(vx2);
    float2 wf = __bfloat1622float2(vw2);

    float y0 = (xf.x * inv_rms) * wf.x;
    float y1 = (xf.y * inv_rms) * wf.y;

    st_bf16x2_any(y + base + col, __floats2bfloat162_rn(y0, y1));
  }
}

__global__ void rmsnorm_h7168_kernel_globalw(
    const __nv_bfloat16* __restrict__ x,
    const __nv_bfloat16* __restrict__ w,
    __nv_bfloat16* __restrict__ y,
    int64_t batch_size) {

  int row = (int)blockIdx.x;
  if ((int64_t)row >= batch_size) return;

  constexpr int H = HIDDEN_SIZE_7168;
  constexpr int VEC2 = H / 2;

  const int tid = threadIdx.x;
  const int base = row * H;

  float sumsq = 0.f;

#pragma unroll 4
  for (int i = tid; i < VEC2; i += (int)blockDim.x) {
    int col = i * 2;
    __nv_bfloat162 vx2 = ld_bf16x2_any(x + base + col);
    float2 xf = __bfloat1622float2(vx2);
    sumsq = fmaf(xf.x, xf.x, sumsq);
    sumsq = fmaf(xf.y, xf.y, sumsq);
  }

  float total = block_sum(sumsq);
  float inv_rms = rsqrtf(total * (1.0f / (float)H) + RMSNORM_EPS);

#pragma unroll 4
  for (int i = tid; i < VEC2; i += (int)blockDim.x) {
    int col = i * 2;

    __nv_bfloat162 vx2 = ld_bf16x2_any(x + base + col);
    __nv_bfloat162 vw2 = ld_bf16x2_any(w + col);

    float2 xf = __bfloat1622float2(vx2);
    float2 wf = __bfloat1622float2(vw2);

    float y0 = (xf.x * inv_rms) * wf.x;
    float y1 = (xf.y * inv_rms) * wf.y;

    st_bf16x2_any(y + base + col, __floats2bfloat162_rn(y0, y1));
  }
}

void rmsnorm_h7168_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int64_t batch_size,
    cudaStream_t stream) {

  if (batch_size <= 0) return;

  // 256 threads is a good default on SM80; 7168 elements => enough work per block.
  constexpr int THREADS = 256;
  dim3 block(THREADS);
  dim3 grid((unsigned int)batch_size);

  // Safer constant-memory init:
  // - Use cudaGetDeviceProperties to ensure symbol exists per device context.
  // - Use synchronous cudaMemcpyToSymbol (not Async) to avoid lifetime/order issues in some harnesses.
  static bool c_weight_initialized = false;
  static int device_cached = -1;

  int dev = -1;
  cudaError_t st_dev = cudaGetDevice(&dev);
  if (st_dev != cudaSuccess) {
    // fallback
    rmsnorm_h7168_kernel_globalw<<<grid, block, 0, stream>>>(hidden_states, weight, output, batch_size);
    return;
  }

  if (!c_weight_initialized || device_cached != dev) {
    cudaError_t st = cudaMemcpyToSymbol(
        c_weight, weight, HIDDEN_SIZE_7168 * sizeof(__nv_bfloat16), 0, cudaMemcpyDeviceToDevice);
    if (st == cudaSuccess) {
      c_weight_initialized = true;
      device_cached = dev;
    } else {
      // clear error and fall back
      cudaGetLastError();
      c_weight_initialized = false;
      device_cached = dev;
    }
  }

  if (c_weight_initialized) {
    rmsnorm_h7168_kernel_constw<<<grid, block, 0, stream>>>(hidden_states, output, batch_size);
  } else {
    rmsnorm_h7168_kernel_globalw<<<grid, block, 0, stream>>>(hidden_states, weight, output, batch_size);
  }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <sstream>
#include <stdexcept>

#include "kernel.h"

static void check_cuda_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " must be a defined tensor";
    throw std::invalid_argument(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
}

torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
  check_cuda_contig(hidden_states, "hidden_states");
  check_cuda_contig(weight, "weight");

  if (hidden_states.dtype() != torch::kBFloat16) {
    throw std::invalid_argument("hidden_states must have dtype torch.bfloat16");
  }
  if (weight.dtype() != torch::kBFloat16) {
    throw std::invalid_argument("weight must have dtype torch.bfloat16");
  }

  if (hidden_states.dim() != 2) {
    throw std::invalid_argument("hidden_states must be 2D [batch_size, 7168]");
  }
  if (weight.dim() != 1) {
    throw std::invalid_argument("weight must be 1D [7168]");
  }

  const int64_t B = hidden_states.size(0);
  const int64_t H = hidden_states.size(1);
  if (H != HIDDEN_SIZE_7168) {
    std::ostringstream oss; oss << "hidden_states.size(1) must be 7168, got " << H;
    throw std::invalid_argument(oss.str());
  }
  if (weight.size(0) != HIDDEN_SIZE_7168) {
    std::ostringstream oss; oss << "weight.size(0) must be 7168, got " << weight.size(0);
    throw std::invalid_argument(oss.str());
  }

  auto output = torch::empty_like(hidden_states);

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  const __nv_bfloat16* x_ptr =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* w_ptr =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* y_ptr =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  rmsnorm_h7168_launch(x_ptr, w_ptr, y_ptr, B, stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA error after rmsnorm_h7168_launch: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

// kwargs-capable wrapper (PyTorch will pass positional args; this keeps API stable)
torch::Tensor run_kwargs(torch::Tensor hidden_states, torch::Tensor weight) {
  return run(hidden_states, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "rmsnorm_h7168 (CUDA)");
  m.def("run_kwargs", &run_kwargs, "rmsnorm_h7168 (CUDA, kwargs helper)");
}
